// src/context/AuthContext.js
import React, { createContext, useState, useContext, useEffect } from 'react';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Al cargar la app, verificamos si hay sesión
    const savedUser = localStorage.getItem('user-session');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  const login = (userData) => {
    setUser(userData);
    localStorage.setItem('user-session', JSON.stringify(userData));
  };

  const logout = () => {
    setUser(null);
    localStorage.clear(); // Limpia todo para seguridad
    window.location.href = "/";
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, loading, isAdmin: user?.rol === 'vendedor' }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

// Hook personalizado para usar el contexto fácilmente
export const useAuth = () => useContext(AuthContext);
